function App() {
  const [view, setView] = useState<'intro' | 'test' | 'calculating' | 'result' | 'admin'>('intro');
  const [answers, setAnswers] = useState<Record<string, number>>({});
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [results, setResults] = useState<CourseResult[]>([]);

  // Admin simple protection
  const [adminClickCount, setAdminClickCount] = useState(0);

  // Load standard 36 questions (taking first 36 from constants for this demo)
  // In a full implementation, we would shuffle or pick adaptively.
  const activeQuestions = useMemo(() => QUESTIONS.slice(0, QUESTIONS_PER_TEST), []);

  useEffect(() => {
    // Autosave check
    const saved = localStorage.getItem('career_test_answers');
    if (saved && view === 'intro') {
       // Optional: restore logic
    }
  }, [view]);

  const handleStart = () => {
    setView('test');
    window.scrollTo(0,0);
  };

  const handleAnswer = (value: number) => {
    const question = activeQuestions[currentQIndex];
    const newAnswers = { ...answers, [question.id]: value };
    setAnswers(newAnswers);
    localStorage.setItem('career_test_answers', JSON.stringify(newAnswers));

    // Wait a bit for animation
    setTimeout(() => {
        if (currentQIndex < activeQuestions.length - 1) {
            setCurrentQIndex(prev => prev + 1);
            window.scrollTo(0,0);
        } else {
            finishTest(newAnswers);
        }
    }, 250); // slight delay for user to see selection
  };

  const finishTest = (finalAnswers: Record<string, number>) => {
    setView('calculating');
    setTimeout(() => {
        const calculated = calculateResults(finalAnswers);
        setResults(calculated);
        setView('result');
        window.scrollTo(0,0);
    }, 1500);
  };

  const handleRestart = () => {
    setAnswers({});
    setCurrentQIndex(0);
    setResults([]);
    localStorage.removeItem('career_test_answers');
    setView('intro');
  };

  // Admin secret trigger
  const handleLogoClick = () => {
    setAdminClickCount(prev => {
        const newCount = prev + 1;
        if (newCount === 5) {
            setView('admin');
            return 0;
        }
        return newCount;
    });
  };

  // --- Views ---

  if (view === 'admin') {
    return <AdminView onLogout={() => setView('intro')} />;
  }

  if (view === 'intro') {
    return (
      <div className="min-h-screen flex flex-col">
        <Header />
        <main className="flex-1 flex flex-col items-center justify-center p-6 text-center max-w-2xl mx-auto">
          <div className="mb-8 p-4 bg-blue-50 rounded-full text-blue-600 animate-bounce">
            <Brain size={64} />
          </div>
          <h1 className="text-4xl md:text-5xl font-bold text-slate-900 mb-6">
            Kelajak kasbingizni <span className="text-blue-600">aniqlang</span>
          </h1>
          <p className="text-lg text-slate-600 mb-10 leading-relaxed">
            DATA Ta'lim Stansiyasi tomonidan ishlab chiqilgan maxsus algoritm yordamida, 
            36 ta savolga javob berib, o'z qobiliyatingizga mos IT yo'nalishni toping.
          </p>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-4 w-full mb-10 text-left">
            {[
                { icon: BarChart2, text: "Aniq tahlil" },
                { icon: ShieldCheck, text: "Ilmiy yondashuv" },
                { icon: CheckCircle2, text: "Tezkor natija" }
            ].map((item, i) => (
                <div key={i} className="flex items-center gap-3 p-4 bg-white rounded-xl shadow-sm border border-slate-100">
                    <item.icon className="text-blue-500" size={20} />
                    <span className="font-medium text-slate-700">{item.text}</span>
                </div>
            ))}
          </div>

          <Button onClick={handleStart} className="w-full md:w-auto text-lg px-10 py-4 shadow-xl shadow-blue-200">
            Testni boshlash <ArrowRight className="inline ml-2" size={20} />
          </Button>

          <div className="mt-20 pt-4 border-t w-full text-slate-400 text-sm cursor-pointer" onClick={handleLogoClick}>
            &copy; 2024 DATA Ta'lim Stansiyasi
          </div>
        </main>
      </div>
    );
  }

  if (view === 'calculating') {
    return (
        <div className="min-h-screen flex flex-col items-center justify-center bg-white">
            <div className="w-16 h-16 border-4 border-blue-200 border-t-blue-600 rounded-full animate-spin mb-6"></div>
            <h2 className="text-2xl font-bold text-slate-800 animate-pulse">Natijalar tahlil qilinmoqda...</h2>
            <p className="text-slate-500 mt-2">Sun'iy intellekt javoblaringizni o'rganmoqda</p>
        </div>
    );
  }

  if (view === 'result') {
    const top1 = results[0];
    const top2 = results[1];

    // Prepare data for chart (Top 5)
    const chartData = results.slice(0, 5).map(r => ({
        name: COURSE_NAMES[r.course].split(' ')[0], // Shorten name
        score: r.percentage
    }));

    return (
      <div className="min-h-screen bg-slate-50 pb-20">
        <Header />
        <main className="max-w-4xl mx-auto p-6">
          <div className="text-center mb-10 fade-in">
            <h2 className="text-3xl font-bold text-slate-900 mb-2">Sizning natijalaringiz</h2>
            <p className="text-slate-600">Javoblaringiz asosida sizga quyidagi yo'nalishlar mos keldi:</p>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mb-12 fade-in">
             <ResultCard result={top1} rank={1} />
             <ResultCard result={top2} rank={2} />
          </div>

          {/* Chart Section */}
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 mb-10 fade-in">
            <h3 className="text-lg font-bold text-slate-800 mb-6 flex items-center gap-2">
                <BarChart2 className="text-blue-500" />
                Umumiy moslik darajasi
            </h3>
            <div className="h-64 w-full">
                <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={chartData} layout="vertical" margin={{ top: 5, right: 30, left: 40, bottom: 5 }}>
                        <XAxis type="number" hide />
                        <YAxis dataKey="name" type="category" width={100} tick={{fontSize: 12}} />
                        <Tooltip 
                            cursor={{fill: 'transparent'}}
                            contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 12px rgba(0,0,0,0.1)' }}
                        />
                        <Bar dataKey="score" radius={[0, 4, 4, 0]} barSize={20}>
                            {chartData.map((entry, index) => (
                                <Cell key={`cell-${index}`} fill={index === 0 ? '#2563eb' : index === 1 ? '#60a5fa' : '#cbd5e1'} />
                            ))}
                        </Bar>
                    </BarChart>
                </ResponsiveContainer>
            </div>
          </div>

          <div className="flex justify-center">
            <Button variant="ghost" onClick={handleRestart} className="flex items-center gap-2 text-slate-500">
                <RefreshCcw size={16} /> Testni qayta ishlash
            </Button>
          </div>
        </main>
      </div>
    );
  }

  // Test View
  const currentQ = activeQuestions[currentQIndex];

  return (
    <div className="min-h-screen flex flex-col bg-slate-50">
      <Header />
      <div className="flex-1 max-w-3xl w-full mx-auto p-4 md:p-8 flex flex-col">
        <div className="mb-4 flex justify-between items-end text-sm text-slate-500 font-medium">
            <span>Savol {currentQIndex + 1} / {activeQuestions.length}</span>
            <span>{Math.round(((currentQIndex + 1) / activeQuestions.length) * 100)}%</span>
        </div>
        <ProgressBar current={currentQIndex + 1} total={activeQuestions.length} />

        <div className="bg-white rounded-2xl shadow-lg p-6 md:p-12 flex-1 flex flex-col items-center justify-center text-center fade-in key-{currentQIndex}">
            <span className="inline-block px-3 py-1 bg-indigo-50 text-indigo-600 rounded-full text-xs font-bold mb-6 uppercase tracking-wider">
                {currentQ.section}
            </span>
            <h2 className="text-2xl md:text-3xl font-bold text-slate-800 mb-12 leading-tight">
                {currentQ.text}
            </h2>

            <LikertScale 
                selectedValue={answers[currentQ.id] ?? null} 
                onChange={handleAnswer} 
            />
        </div>

        <div className="text-center mt-8 text-slate-400 text-sm">
            O'ylanmasdan, birinchi kelgan fikrni belgilang.
        </div>
      </div>
    </div>
  );
}

export default App;
